if (!cgJsClass.gallery.rating.resolveInteractionGid) {
    cgJsClass.gallery.rating.resolveInteractionGid = function (gid, $element) {
        var candidates = [];
        var seen = {};
        var $contextElement;
        var shortcodeName = '';
        var resolvedGid = gid;

        var addCandidate = function (candidate) {
            if (candidate === undefined || candidate === null) {
                return;
            }

            candidate = String(candidate).trim();

            if (!candidate || seen[candidate]) {
                return;
            }

            seen[candidate] = true;
            candidates.push(candidate);
        };

        addCandidate(gid);

        if ($element && $element.length) {
            addCandidate($element.attr('data-cg-gid'));

            $element.parents('[data-cg-gid]').each(function () {
                addCandidate(jQuery(this).attr('data-cg-gid'));
            });

            $contextElement = $element.closest('.cgCenterDiv[data-cg-gid], .cgCenterDivPhpLoad[data-cg-gid], .mainCGallery[data-cg-gid], .mainCGdiv[data-cg-gid], .mainCGdivHelperParent[data-cg-gid]');
            if ($contextElement.length) {
                addCandidate($contextElement.first().attr('data-cg-gid'));
            }

            shortcodeName = $element.attr('data-cg-shortcode') ||
                $element.closest('[data-cg-shortcode]').attr('data-cg-shortcode') ||
                $element.find('[data-cg-shortcode]').first().attr('data-cg-shortcode') ||
                '';
        }

        candidates.some(function (candidate) {
            if (shortcodeName === 'cg_gallery_user' && /^[0-9]+$/.test(candidate)) {
                candidate = candidate + '-u';
                if (cgJsData[candidate] && cgJsData[candidate].vars && cgJsData[candidate].options) {
                    resolvedGid = candidate;
                    return true;
                }
            }

            if (cgJsData[candidate] && cgJsData[candidate].vars && cgJsData[candidate].options) {
                resolvedGid = candidate;
                return true;
            }

            return false;
        });

        return resolvedGid;
    };
}

if (!cgJsClass.gallery.rating.getGalleryDataForInteraction) {
    cgJsClass.gallery.rating.getGalleryDataForInteraction = function (gid, $element) {
        gid = cgJsClass.gallery.rating.resolveInteractionGid(gid, $element);

        if (!gid || !cgJsData[gid] || !cgJsData[gid].vars || !cgJsData[gid].options) {
            return null;
        }

        return cgJsData[gid];
    };
}

if (!cgJsClass.gallery.rating.bindActionCardRatingProxy) {
    cgJsClass.gallery.rating.bindActionCardRatingProxy = function () {
        if (cgJsClass.gallery.vars.eventClickActionCardRatingProxy) {
            return;
        }

        cgJsClass.gallery.vars.eventClickActionCardRatingProxy = true;

        jQuery(document).on('click', '.cg-runtime-single-view-action-card-rating, .cg-center-image-action-card-rating', function (e) {
            var $card = jQuery(this);
            var $target = jQuery(e.target);
            var $proxyTarget = jQuery();

            if (
                $target.closest('.cg_rate_minus, .cg_rate_minus_five_star').length ||
                $target.closest('.cg_gallery_rating_div_five_star_details, .cg_gallery_rating_div_five_star_details_close_button').length
            ) {
                return;
            }

            if (
                $target.closest('.cg_rate_star').length ||
                $target.closest('.cg_gallery_rating_div_child_five_star').length
            ) {
                return;
            }

            $proxyTarget = $card.find('.cg_gallery_rating_div_child_five_star').first();

            if (!$proxyTarget.length) {
                $proxyTarget = $card.find('.cg_rate_star').not('.cg_gallery_rating_overview .cg_rate_star').first();
            }

            if (!$proxyTarget.length) {
                return;
            }

            e.preventDefault();
            e.stopPropagation();
            $proxyTarget.trigger('click');
        });
    };
}

if (!cgJsClass.gallery.rating.getInteractionShortcodeName) {
    cgJsClass.gallery.rating.getInteractionShortcodeName = function (galleryData, $element) {
        if (galleryData && galleryData.vars && galleryData.vars.shortcode_name) {
            return galleryData.vars.shortcode_name;
        }

        if ($element && $element.length) {
            return $element.attr('data-cg-shortcode') ||
                $element.closest('[data-cg-shortcode]').attr('data-cg-shortcode') ||
                $element.find('[data-cg-shortcode]').first().attr('data-cg-shortcode') ||
                '';
        }

        return '';
    };
}

if (!cgJsClass.gallery.rating.isUserGalleryInteraction) {
    cgJsClass.gallery.rating.isUserGalleryInteraction = function (gid, galleryData, $element) {
        var shortcodeName = cgJsClass.gallery.rating.getInteractionShortcodeName(galleryData, $element);

        return !!(
            (galleryData && galleryData.vars && galleryData.vars.isUserGallery) ||
            String(gid).indexOf('-u') >= 0 ||
            shortcodeName === 'cg_gallery_user'
        );
    };
}

if (!cgJsClass.gallery.rating.isVoteBlockedForContext) {
    cgJsClass.gallery.rating.isVoteBlockedForContext = function (gid, realId, minusVoteNow, $element) {
        gid = cgJsClass.gallery.rating.resolveInteractionGid(gid, $element);

        var galleryData = cgJsClass.gallery.rating.getGalleryDataForInteraction(gid, $element);
        var rawDataEntry;
        var entryWpUserId = 0;
        var currentWpUserId = parseInt(cgJsClass.gallery.vars.wpUserId, 10) || 0;
        var voteNotOwnImageActive;
        var isCheckCookieActive;
        var isCheckLoginActive;

        if (!galleryData) {
            return false;
        }

        if (cgJsClass.gallery.rating.isUserGalleryInteraction(gid, galleryData, $element)) {
            return true;
        }

        voteNotOwnImageActive = !!(
            galleryData.options &&
            galleryData.options.pro &&
            parseInt(galleryData.options.pro.VoteNotOwnImage, 10) === 1
        );
        isCheckCookieActive = !!(
            galleryData.options &&
            galleryData.options.general &&
            parseInt(galleryData.options.general.CheckCookie, 10) === 1
        );
        isCheckLoginActive = !!(
            galleryData.options &&
            galleryData.options.general &&
            parseInt(galleryData.options.general.CheckLogin, 10) === 1
        );

        if (!voteNotOwnImageActive || isCheckCookieActive || !isCheckLoginActive || minusVoteNow) {
            return false;
        }

        if (!realId || !currentWpUserId) {
            return false;
        }

        if (galleryData.vars.rawData && galleryData.vars.rawData[realId]) {
            rawDataEntry = galleryData.vars.rawData[realId];
            entryWpUserId = parseInt(rawDataEntry.WpUserId, 10) || 0;
        }

        if (!entryWpUserId && galleryData.vars.mainDataWpUserIds && galleryData.vars.mainDataWpUserIds[realId]) {
            entryWpUserId = parseInt(galleryData.vars.mainDataWpUserIds[realId], 10) || 0;
        }

        if (!entryWpUserId && galleryData.imagesFullData && galleryData.imagesFullData[realId]) {
            entryWpUserId = parseInt(galleryData.imagesFullData[realId].WpUserId, 10) || 0;
        }

        return !!entryWpUserId && entryWpUserId === currentWpUserId;
    };
}

if (!cgJsClass.gallery.rating.showOwnEntryVoteBlockedMessage) {
    cgJsClass.gallery.rating.showOwnEntryVoteBlockedMessage = function (gid, $element) {
        gid = cgJsClass.gallery.rating.resolveInteractionGid(gid, $element);

        var galleryData = cgJsClass.gallery.rating.getGalleryDataForInteraction(gid, $element);
        var galleryLanguage = cgJsClass.gallery.language[gid] || {};
        var isUserGalleryContext = cgJsClass.gallery.rating.isUserGalleryInteraction(gid, galleryData, $element);
        var message = isUserGalleryContext ?
            (galleryLanguage.YouCanNotVoteInOwnGallery || 'You can not vote in own gallery') :
            (galleryLanguage.ItIsNotAllowedToVoteForYourOwnPicture || 'You cannot vote for your own entry');

        cgJsClass.gallery.function.message.show(gid, message);
    };
}

if (!cgJsClass.gallery.rating.openReadOnlyRatingGalleryEntry) {
    cgJsClass.gallery.rating.openReadOnlyRatingGalleryEntry = function (gid, realId, $element) {
        var galleryData;
        var ratingTargets;
        var $cgShow = jQuery();
        var $clickTarget = jQuery();

        gid = cgJsClass.gallery.rating.resolveInteractionGid(gid, $element);
        realId = parseInt(realId, 10);
        galleryData = cgJsClass.gallery.rating.getGalleryDataForInteraction(gid, $element);

        if (!galleryData || !realId) {
            return false;
        }

        if ($element && $element.length) {
            if ($element.closest('.cgCenterDiv').length && !$element.closest('.cg_show').length) {
                return false;
            }

            if ($element.closest('.mainCGslider').length) {
                return false;
            }

            $cgShow = $element.closest('.cg_show');
        }

        if ((!$cgShow.length || !$cgShow.hasClass('cg_show')) && cgJsClass.gallery.rating.getSingleEntryRatingTargets) {
            ratingTargets = cgJsClass.gallery.rating.getSingleEntryRatingTargets(gid, realId);
            if (ratingTargets && ratingTargets.imageObject && ratingTargets.imageObject.length) {
                $cgShow = ratingTargets.imageObject.closest('.cg_show');
                if (!$cgShow.length) {
                    $cgShow = ratingTargets.imageObject;
                }
            }
        }

        if ((!$cgShow.length || !$cgShow.hasClass('cg_show')) && galleryData.vars && galleryData.vars.mainCGallery) {
            $cgShow = galleryData.vars.mainCGallery.find('#cg_show' + realId).first();
        }

        if (!$cgShow.length || !$cgShow.hasClass('cg_show')) {
            return false;
        }

        $clickTarget = $cgShow.find('.cg_gallery_info').first();
        if (!$clickTarget.length) {
            $clickTarget = $cgShow.find('.cg_gallery_info_title').first();
        }
        if (!$clickTarget.length) {
            $clickTarget = $cgShow.find('.cg_append').first();
        }
        if (!$clickTarget.length) {
            $clickTarget = $cgShow;
        }

        $clickTarget.trigger('click');
        return true;
    };
}

