    if (cgJsData[gid].vars.getJson.length > 0 && openPage === false) {
        cgJsClass.gallery.getJson.abortGetJson(gid);
    }
        
    // Enforce masonry look for CGalleries
    if (cgJsData[gid].vars.isCGalleries) {
        cgJsData[gid].vars.currentLook = 'masonry';
    }

    // Adjust current look based on specific conditions
    if (cgJsData[gid].vars.currentLook === 'thumb' && !sliderView) {
        cgJsData[gid].vars.currentLook = 'masonry';
    } else if (cgJsData[gid].vars.currentLook === 'height') {
        cgJsData[gid].vars.currentLook = 'masonry';
    }

    // Initialize the appropriate gallery view logic based on the current look
