        $(document).on('click', '.mainCGBackToGalleryButtonHref', function (e) {
            var $backLink = $(this);
            var gid = $backLink.closest('.mainCGdiv').attr('data-cg-gid');
            var historyUrl;
            var galleriesPageNumber = 1;

            if ($backLink.hasClass('isCGalleries')) {
                if (!gid || !cgJsData[gid] || !cgJsData[gid].vars) {
                    return;
                }

                historyUrl = $backLink.prop('href') || $backLink.attr('href') || '';
                if (!historyUrl) {
                    return;
                }

                try {
                    var historyUrlObject = new URL(historyUrl, window.location.origin);
                    if (historyUrlObject.origin !== window.location.origin) {
                        return;
                    }
                    galleriesPageNumber = parseInt(historyUrlObject.searchParams.get('cgl_page'), 10) || 1;
                    galleriesPageNumber = galleriesPageNumber > 0 ? galleriesPageNumber : 1;
                } catch (error) {
                    return;
                }

                e.preventDefault();
                cgJsClass.gallery.getJson.getGallery(gid, '9999999', cgJsData[gid].vars.shortcode_name, null, {
                    galleriesPageNumber: galleriesPageNumber,
                    historyUrl: historyUrl,
                    historyMode: 'push'
                });
            } else {
                cgJsClass.gallery.function.general.tools.setSessionStorageItem('mainCGBackToGalleryButtonHrefGid', $backLink.attr('data-cg-gid'));
            }
        });

