        $(document).on('click', '.cg_append, .cg_append_overlay, .cg_append_social_overlay, .cg_gallery_info, .cg_gallery_info_title, article.cg_show', function (e) {
            var timeMilliseconds = (new Date().getTime());
            var $element;
            var $mainCGallery;
            var gid;
            var $cg_show;
            var $mainCGslider;
            var sliderView = false;
            var order;
            var targetData;
            var realId;
            var isGalleryOpened = false;
            var initFullWindow = false;
            var isGalleryOpenedSliderLook = false;
            var direction = undefined;
            var isBlogEntryClick = false;
            var isNonBlogGalleryTileClick = false;
            var isRatingOriginClick = false;
            var openFullwindowEntry;

            if (eventTime) {
                if (timeMilliseconds - 10 <= eventTime) {
                    return;
                }
            }

            eventTime = timeMilliseconds;

            if ($(e.target).closest('.cgCenterDiv').length || $(e.target).hasClass('cg_extern_privacy_policy')) {
                return;
            }
            
            if ($(this).hasClass('cg_append_overlay')) {
                $element = $(this).closest('.cg_append_container').find('.cg_append');
            } else {
                $element = $(this);
            }
            
            $mainCGallery = $element.closest('.mainCGallery');
            gid = $mainCGallery.attr('data-cg-gid');

            if (!gid || typeof cgJsData == 'undefined' || !cgJsData[gid] || !cgJsData[gid].vars || !cgJsData[gid].options) {
                return;
            }

            if (cgJsData[gid] &&
                cgJsData[gid].options &&
                cgJsData[gid].options.general &&
                cgJsData[gid].options.general.RatingOutGallery == 1) {
                isRatingOriginClick = !!$(e.target).closest('.cg_gallery_rating_div, .cg_gallery_rating_div_child, .cg_gallery_rating_div_five_star_details, .cg_rate_star, .cg_rate_minus, .cg_rate_star_five_star, .cg_rate_minus_five_star, .cg_voted_confirm, .cg_gallery_rating_div_count').length;
            }

            if (isRatingOriginClick) {
                return;
            }

            if (($(e.target).hasClass('cg_forward_to_url') || $(e.target).find('.cg_forward_to_url').length || $(e.target).closest('.cg_forward_to_url').length) && cgJsData[gid].vars.currentLook != 'slider') {
                return;
            }

            if ($(e.target).hasClass('cg_delete_user_image') || $(e.target).hasClass('cg_social_consent_agree') || $(this).hasClass('cg_gallery_info_href') || $(e.target).closest('.cg_gallery_info_href').length) {
                return;
            }

            $cg_show = $element.closest('.cg_show');

            if ($(this).closest('.isCGalleries').length) {
                var targetGalleryId;

                if (cgJsData[gid].vars.isGalleriesMainPage) {
                    if (triggerGalleryInfoRedirect(e, $cg_show, $(e.target))) {
                        return;
                    }
                    return;
                }

                if (isModifiedNavigationClick(e) && getGalleryInfoRedirectAnchor($cg_show).length) {
                    return;
                }

                e.preventDefault();
                targetGalleryId = getCGalleriesTargetGalleryId(gid, $cg_show);

                if (!targetGalleryId) {
                    cgJsClass.gallery.function.message.showPro(gid, 'Gallery data could not be requested. Please contact administrator.');
                    return;
                }

                cgJsClass.gallery.getJson.getGallery(gid, targetGalleryId, cgJsData[gid].vars.shortcode_name, $cg_show.attr('data-cg-id'));
                return;
            }

            $mainCGslider = $element.closest('.mainCGslider');

            if (!cgJsData[gid].vars.isUserGallery && !cgJsData[gid].vars.isOnlyGalleryNoVoting && !cgJsData[gid].vars.isOnlyGalleryWinner) {
                if ($cg_show.length && !$mainCGslider.length) {
                    if (!$(e.target).hasClass('cg_voted_confirm')) {
                        // Empty block retained for structural alignment with legacy code
                    }
                }
            }

            if (cgJsData[gid].vars.isUserGallery) {
                if ($(e.target).closest('.cg-center-image-parent').length) {
                    return;
                }
            }

            if (cgJsData[gid].options.pro.IsModernFiveStar == 1 && cgJsData[gid].options.general.RatingOutGallery == 1 && cgJsClass.gallery.vars.isMobile && !$(this).hasClass('cg-pass-through') && !cgJsClass.gallery.vars.passThrough) {
                if (($(e.target).closest('.cg_gallery_rating_div_child').length == 1 && $(e.target).closest('.cg-center-image-rating-div').length == 0) || ($(e.target).hasClass('.cg_gallery_rating_div_child') && $(e.target).closest('.cg-center-image-rating-div').length == 0)) {
                    if (!$mainCGslider.length) {
                        return;
                    }
                }
            }

            if (cgJsData[gid].options.pro.IsModernFiveStar == 1 && cgJsData[gid].options.general.AllowRatingDynamic) {
                if ($mainCGslider.length >= 1) {
                    $cg_show = $(this).closest('.cg_show');
                    if ($cg_show.length >= 1) {
                        if (cgJsData[gid].options.general.FullSizeImageOutGallery != 1 && cgJsData[gid].options.general.OnlyGalleryView != 1) {
                            $cg_show.find('.cg_gallery_rating_div_five_star_details').addClass('cg_hide');
                        }
                    }
                }
            }

            $(this).removeClass('cg-pass-through');
            cgJsClass.gallery.vars.passThrough = false;
            cgJsClass.gallery.vars.showImageClicked = true;
            cgJsClass.gallery.function.general.tools.checkErrorAbort(gid);

            if (cgJsData[gid].vars.currentLook == 'slider') {
                sliderView = true;
            }

            targetData = getGalleryClickTargetData(gid, $cg_show, $element);
            if (!targetData) {
                return;
            }

            order = targetData.order;
            realId = targetData.realId;
            $cg_show.attr('data-cg-order', order);

            if (getGalleryConsentInteraction(gid, realId).isForwardToUrl && sliderView == false) {
                if (triggerGalleryInfoRedirect(e, $cg_show, $(e.target), true)) {
                    return;
                }
            }

            if ((cgJsData[gid].options.general.FullSizeImageOutGallery == 1 || cgJsData[gid].options.general.OnlyGalleryView == 1 || cgJsData[gid].options.visual.ForwardToWpPageEntry == 1) && sliderView == false) {
                if ((cgJsData[gid].options.general.FullSizeImageOutGallery == 1 || cgJsData[gid].options.visual.ForwardToWpPageEntry == 1) && triggerGalleryInfoRedirect(e, $cg_show, $(e.target))) {
                    return;
                }
                return;
            }

            e.preventDefault();
            isBlogEntryClick = !!$element.closest('.cgCenterDivForBlogView').length;
            isNonBlogGalleryTileClick = !!($cg_show.length && !$mainCGslider.length && !isBlogEntryClick);

            cgJsClass.gallery.views.functions.appendAndRemoveImagesInSlider(gid, order, cgJsData[gid].vars.maximumVisibleImagesInSlider, cgJsData[gid].vars.mainCGslider);

            if (cgJsData[gid].options.pro.SliderFullWindow == 1 || cgJsData[gid].options.visual.BlogLookFullWindow == 1) {
                initFullWindow = true;
            }

            openFullwindowEntry = function () {
                cgJsData[gid].vars.openedRealId = realId;
                cgJsData[gid].vars.openedGalleryImageOrder = order;
                cgJsClass.gallery.vars.openedRealId = realId;
                cgJsClass.gallery.vars.openedGalleryImageOrder = order;
                cgJsClass.gallery.views.fullwindow.openFunction(gid, $('<div data-cg-real-id="' + realId + '" data-cg-order="' + order + '"></div>'));
            };

            if (((cgJsData[gid].options.general.FullSizeSlideOutStart == 1 || cgJsData[gid].options.pro.SliderFullWindow == 1 || cgJsData[gid].options.visual.BlogLookFullWindow == 1) &&
                !cgJsClass.gallery.vars.fullwindow && !cgJsData[gid].vars.galleryAlreadyFullWindow) ||
                (!cgJsClass.gallery.vars.fullwindow && initFullWindow == true)) {

                if (cgJsData[gid].options.visual.BlogLookFullWindow == 1 && isNonBlogGalleryTileClick) {
                    if (typeof $element.find('.cg_rate_star')[0] == 'undefined' && $element.hasClass('cg_gallery_info')) {
                        if (cgJsClass.gallery.function.general.tools.checkIfNoRating(gid)) {
                            openFullwindowEntry();
                        } else {
                            return;
                        }
                    } else {
                        openFullwindowEntry();
                    }
                    return;
                }

                if (!sliderView && cgJsData[gid].vars.currentLook != 'blog') {
                    if (typeof $element.find('.cg_rate_star')[0] == 'undefined' && $element.hasClass('cg_gallery_info')) {
                        if (cgJsClass.gallery.function.general.tools.checkIfNoRating(gid)) {
                            openFullwindowEntry();
                        } else {
                            return;
                        }
                    } else {
                        openFullwindowEntry();
                    }
                    return;
                }
            }

            if ($element.hasClass('cg_open_gallery')) {
                $element.removeClass('cg_open_gallery');
                isGalleryOpened = true;
            }
            
            if ($element.hasClass('cg_open_gallery_slider_look')) {
                $element.removeClass('cg_open_gallery_slider_look');
                if (sliderView == true) {
                    isGalleryOpenedSliderLook = true;
                }
            }

            if (typeof cgJsData[gid].vars.openedGalleryImageOrder != null) {
                if (parseInt(order, 10) >= parseInt(cgJsData[gid].vars.openedGalleryImageOrder, 10)) {
                    direction = 'right';
                }
                if (parseInt(order, 10) < parseInt(cgJsData[gid].vars.openedGalleryImageOrder, 10)) {
                    direction = 'left';
                }
            }

            if (typeof $element.find('.cg_rate_star')[0] == 'undefined' && $element.hasClass('cg_gallery_info')) {
                if (cgJsClass.gallery.function.general.tools.checkIfNoRating(gid)) {
                    cgJsClass.gallery.views.singleView.openImage($, order, false, gid, direction, isGalleryOpened, isGalleryOpenedSliderLook);
                } else {
                    return;
                }
            } else {
                cgJsClass.gallery.views.singleView.openImage($, order, false, gid, direction, isGalleryOpened, isGalleryOpenedSliderLook);
            }
        });

