        var showEntryOwnerProfileImage = function (gid, realId) {
            var ownerData;
            var nicknameHtml;
            var profileImageModal;
            var profileImageAlt;
            var $profileImage;

            if (!gid || !realId || !cgJsData[gid]) {
                return;
            }

            ownerData = cgJsClass.gallery.function.general.tools.getEntryOwnerDisplayData(gid, realId);

            if (!ownerData.hasProfileImage) {
                return;
            }

            if (ownerData.hasNickname) {
                nicknameHtml = '<div class="cg-center-show-profile-image-full-nickname">' + cgJsClass.gallery.function.general.tools.sanitizeOutput(ownerData.nickname) + '</div>';
            } else {
                nicknameHtml = '';
            }

            profileImageModal = ownerData.profileImageModal || ownerData.profileImage;
            profileImageAlt = ownerData.hasNickname ? 'Profile image of ' + cgJsClass.gallery.function.general.tools.sanitizeOutput(ownerData.nickname) : 'Profile image';

            cgJsClass.gallery.function.message.showPro(
                gid,
                nicknameHtml + '<div class="cg-center-show-profile-image-full-show"><img class="cg-center-show-profile-image-full-image" src="' + profileImageModal + '" alt="' + profileImageAlt + '"></div>',
                undefined,
                undefined,
                undefined,
                undefined,
                undefined,
                undefined,
                true
            );

            $profileImage = cgJsClass.gallery.vars.cgMessagesContainerPro.find('.cg-center-show-profile-image-full-image').last();

            if ($profileImage.length) {
                if ($profileImage.get(0).complete) {
                    cgJsClass.gallery.function.message.resize(true);
                } else {
                    $profileImage.one('load', function () {
                        cgJsClass.gallery.function.message.resize(true);
                    });
                }
            }
        };

