        jQuery(document).on('click','.cg-center-image-next-file,.cg-center-image-prev-file',function () {

            var $cgCenterDiv = $(this).closest('.cgCenterDiv');
            var $cgCenterImage = $cgCenterDiv.find('.cg-center-image');
            var $cgCenterImageParent = $cgCenterImage.closest('.cg-center-image-parent');
            $cgCenterImageParent.removeClass('cg-center-image-parent-multiple-files-clicked');
            $cgCenterImage.removeClass('cg_transition');
            $cgCenterImage.css({// reset here
                'background':'',
                'width':'',
                'height':'',
                'max-width':'',
                'max-height':'',
                'top':'',
                'left':'',
                'webkit-transform':'',
                '-moz-transform':'',
                '-ms-transform':'',
                '-o-transform':'',
                'transform':''
            });
            $cgCenterImage.removeClass('cg_background_unset');// the only way to prevent background set from fast clicking in the moment, don't know why
            $cgCenterImage.find('.cg-center-image-rotated').addClass('cg_hide').css('background','');

            var gidForCenterDivElements = $cgCenterDiv.attr('data-cg-gid-with-order');
            var realId = $(this).attr('data-cg-real-id');
            var gid = $(this).attr('data-cg-gid');

            cgJsClass.gallery.views.singleViewFunctions.removeEmbed($cgCenterDiv);
            cgJsClass.gallery.views.singleViewFunctions.removeClassEmbed($cgCenterImage);

            if(cgJsData[gid].imageObject[realId]){
                cgJsData[gid].imageObject[realId].isAdditionalFileChanged = true;
            }

            if($(this).hasClass('cg-center-image-next-file')){
                var minus = '';// direction right
                cgJsClass.gallery.views.singleViewFunctions.setSelectedFileInMultipleFiles(gid,realId,undefined,true,$cgCenterDiv);
            } else if($(this).hasClass('cg-center-image-prev-file')){
                var minus = '-';// direction left
                cgJsClass.gallery.views.singleViewFunctions.setSelectedFileInMultipleFiles(gid,realId,true,undefined,$cgCenterDiv);
            }

            var selectedFile = cgJsData[gid].vars.rawData[realId];
            var isEmbed = cgJsClass.gallery.function.general.tools.isEmbed(gid,realId,selectedFile);
            var isAlternativeFileType = cgJsClass.gallery.function.general.tools.isAlternativeFileType(gid,realId,selectedFile);
            var sliderView = false;
            var spaceForShowExif = cgJsClass.gallery.views.singleViewFunctions.getValidatedMultipleFilesExtraSpace(cgJsData[gid].vars.spaceForShowExif);
            if(cgJsData[gid].vars.currentLook=='slider' || cgJsData[gid].vars.currentLook=='blog'){
                sliderView = true;
            }
            var cgCenterImageParentHeight = parseFloat($cgCenterImageParent.attr('data-cg-multiple-files-height-to-set'));
            var cgCenterImageParentHeightFromDom = parseFloat($cgCenterImageParent.height());
            var cgCenterDivWidth = cgJsData[gid].vars.mainCGallery.width();
            if(sliderView && cgJsData[gid].vars.widthmainForCalculation > cgJsClass.gallery.vars.maxWidthBlogView){
                cgCenterDivWidth = cgJsClass.gallery.vars.maxWidthBlogView;
            }
            cgCenterDivWidth = cgCenterDivWidth - 2;

            if(!cgCenterImageParentHeight && cgJsData[gid].vars.cgCenterImageParentHeight){
                cgCenterImageParentHeight = cgJsData[gid].vars.cgCenterImageParentHeight;
            }
            if(!cgCenterImageParentHeight && cgCenterImageParentHeightFromDom){
                cgCenterImageParentHeight = cgCenterImageParentHeightFromDom;
            }
            if(!cgCenterImageParentHeight){
                cgCenterImageParentHeight = jQuery(window).height() / 5 * 4;
            }

            if(selectedFile.MultipleFilesParsed){
                var cgCenterImageParentHeightFallback = Math.max(
                    cgCenterImageParentHeight,
                    cgCenterImageParentHeightFromDom || 0,
                    cgJsData[gid].vars.cgCenterImageParentHeight || 0,
                    jQuery(window).height() / 5 * 4
                );
                cgCenterImageParentHeight = cgJsClass.gallery.views.singleViewFunctions.getValidatedMultipleFilesHeightValue(
                    gid,
                    cgJsClass.gallery.views.singleViewFunctions.getMultipleFilesHeightToSet(
                        gid,
                        realId,
                        cgCenterDivWidth,
                        cgCenterImageParentHeightFallback,
                        spaceForShowExif
                    ),
                    cgCenterImageParentHeightFallback
                );
                cgJsData[gid].vars.cgCenterImageParentHeight = cgCenterImageParentHeight;
                $cgCenterImageParent.addClass('cg-center-image-parent-multiple-files').attr('data-cg-multiple-files-height-to-set', cgCenterImageParentHeight).css({
                    'min-height': cgCenterImageParentHeight + 'px',
                    'max-height': cgCenterImageParentHeight + 'px',
                    'height': cgCenterImageParentHeight + 'px'
                });
            }
            var ImgType = selectedFile.ImgType;

            $cgCenterDiv.find('.cg-center-image-next-file,.cg-center-image-prev-file').attr({
                'data-cg-img-type': ImgType,
                'data-cg-real-id': realId
            });

            //$cgCenterDiv.find('.cg-center-image-alternative-file-type').addClass('cg_hide');
            $cgCenterDiv.find('.cg-center-image-parent-multiple-files-nav-point').removeClass('cg-center-image-parent-multiple-files-nav-point-active');
            $cgCenterDiv.find('.cg-center-image-parent-multiple-files-nav-point[data-cg-order="'+selectedFile.selectedOrder+'"]').addClass('cg-center-image-parent-multiple-files-nav-point-active');


            var originalSource = cgJsClass.gallery.function.general.tools.checkSsl(cgJsData[gid].vars.rawData[realId]['guid']);

            cgJsClass.gallery.views.singleViewFunctions.setCenterImageDownloadLink(gid,realId,originalSource,ImgType,$cgCenterDiv,$cgCenterImage,selectedFile.PdfOriginal);

            if(isAlternativeFileType){
                cgJsClass.gallery.views.singleViewFunctions.setAlternativeFileTypeOrVideo(gid,realId,$cgCenterImage,selectedFile.ImgType,selectedFile.guid,selectedFile.NamePic,isAlternativeFileType,$cgCenterDiv,false,true);
            }else if(cgJsClass.gallery.function.general.tools.isEmbed(gid,realId)){
                $cgCenterDiv.find('.cg-center-image-download-link').addClass('cg_hide');// has to be done here
                cgJsClass.gallery.views.singleViewFunctions.setEmbed(gid,realId,selectedFile.ImgType,$cgCenterImage,$cgCenterDiv.find('.cg-center-image-parent'),$cgCenterDiv,$cgCenterDiv.width(),$cgCenterDiv.find('.cg-center-image-parent').height());
            }else{

                cgJsClass.gallery.views.singleViewFunctions.setImageWidthHeight(
                    realId,
                    gid,
                    gidForCenterDivElements,
                    selectedFile,
                    sliderView,
                    spaceForShowExif,
                    cgCenterImageParentHeight,
                    selectedFile.rThumb,
                    $cgCenterDiv,
                    $cgCenterImage,
                    minus,
                    false,
                    true
                );
                cgJsClass.gallery.views.singleViewFunctions.showExifData(gid,realId,$cgCenterDiv,gidForCenterDivElements);
                cgJsClass.gallery.views.setWatermarkSingleImageView(realId,gid,cgJsData[gid].vars.info[realId],$cgCenterDiv);

            }

            if($cgCenterDiv.find('.cg-forward-original-file').parent().is('a')){
                if(selectedFile.ImgType=='ytb'){
                    var imageUrl = 'https://www.youtube.com/watch?v='+selectedFile.post_name;
                    $cgCenterDiv.find('.cg-forward-original-file').parent().attr('href',imageUrl);
                }else {
                    if(selectedFile.PdfOriginal){
                        $cgCenterDiv.find('.cg-forward-original-file').parent().attr('href',selectedFile.PdfOriginal);
                    }else{
                        $cgCenterDiv.find('.cg-forward-original-file').parent().attr('href',selectedFile.guid);
                    }

                }
            }

            cgJsClass.gallery.function.general.tools.refreshGalleryLazyLoad(gid);

        });

