cgJsClass.gallery.views.singleViewFunctions.addConsentRequiredClass = function (gid, realId, cgCenterDiv) {
    var hasNoEmbed = false;
    var hasEmbedConfirmed = false;
    var order;
    var ImgType;

    if (cgJsData[gid].vars.rawData[realId].MultipleFilesParsed) {
        for (order in cgJsData[gid].vars.rawData[realId].MultipleFilesParsed) {
            if (!cgJsData[gid].vars.rawData[realId].MultipleFilesParsed.hasOwnProperty(order)) {
                break;
            }
            ImgType = cgJsData[gid].vars.rawData[realId].MultipleFilesParsed[order].ImgType;
            if (!cgJsClass.gallery.function.general.tools.isEmbed(gid, realId, undefined, ImgType)) {
                hasNoEmbed = true;
            } else {
                if (ImgType == 'ytb' && cgJsClass.gallery.function.general.tools.getSessionStorageItem('cgYtbConsentAgreed')) { hasEmbedConfirmed = true; }
                if (ImgType == 'twt' && cgJsClass.gallery.function.general.tools.getSessionStorageItem('cgTwtConsentAgreed')) { hasEmbedConfirmed = true; }
                if (ImgType == 'tkt' && cgJsClass.gallery.function.general.tools.getSessionStorageItem('cgTktConsentAgreed')) { hasEmbedConfirmed = true; }
                if (ImgType == 'inst' && cgJsClass.gallery.function.general.tools.getSessionStorageItem('cgInstConsentAgreed')) { hasEmbedConfirmed = true; }
            }
        }
        if (!hasNoEmbed && !hasEmbedConfirmed) {
            cgCenterDiv.addClass('cg_social_consent_required');
        }
    } else {
        cgCenterDiv.addClass('cg_social_consent_required');
    }
};

