                galleryVars.mainCGdiv.removeClass('cg_blog_view_search cg_fullwindow_blog_view_search');
                galleryVars.mainCGdiv.css('height', 'unset');
                galleryVars.mainCGallery.css('min-height', '');
                galleryVars.cgCenterDivLoaderContainer.find('.cgCenterDiv.cgCenterDivLoader').addClass('cg_hide');
                galleryVars.cgCenterDivLoaderContainer.addClass('cg_hide cg_hidden cg_is_on_search').removeClass('cg_visibility_visible');
                galleryVars.cgCenterDivLoaderContainerBackdrop.addClass('cg_hide cg_hidden').removeClass('cg_visibility_visible');
