cgJsClass.gallery.function.search.input = function ($) {
    if (cgJsClass.gallery.vars.eventCgSearchInput) {
        return;
    } else {
        cgJsClass.gallery.vars.eventCgSearchInput = true;
    }

    // Debounced input handler to avoid excessive processing
    $(document).on('input', '.cg_search_input', function () {
        var $element = $(this);
        clearTimeout(window._cgSearchInputTimeout);
        window._cgSearchInputTimeout = setTimeout(function () {
            cgJsClass.gallery.function.search.inputProcess($element);
        }, 300);
    });

    // Reset URL hash when focusing the search input in fullwindow mode,
    // but keep the compact fullwindow blog slider popover open during search focus.
    $(document).on('focusin', '.cg_search_input', function () {
        var gid = $(this).attr('data-cg-gid');
        var isMobileFullwindowFocus = !!(
            cgJsClass.gallery.vars.fullwindow &&
            cgJsClass.gallery.vars.isMobile
        );

        if (isMobileFullwindowFocus) {
            return;
        }

        if (
            cgJsClass.gallery.vars.fullwindow &&
            !(
                gid &&
                cgJsClass.gallery.views &&
                cgJsClass.gallery.views.functions &&
                cgJsClass.gallery.views.functions.isFullWindowBlogSliderPopoverOpen(gid)
            )
        ) {
            cgJsClass.gallery.vars.isHashJustChangedNewLogic = true;
            location.hash = '#';
        }
    });
};
;/**
 * @ai_scan_directive
 * FUNCTION: Search Data Collector (Contest Gallery)
 * DESCRIPTION: Collects and filters image IDs based on search keywords and category selections.
 * CORE LOGIC:
 * - Keyword Matching: Splits search input into words and checks against full image info strings and user nicknames.
 * - Category Filtering: If the Category Widget is active, it validates matches against current category visibility.
 * - Result Set: Returns an object mapping real IDs to the search string if matched, or an empty string if just filtered by category.
 */

cgJsClass.gallery.function.search.collectData = function (gid) {

    var ids = {};

    var noCategories = false;
    if(cgJsData[gid].options.pro.CatWidget!=1){
        noCategories = true;
    }
    if(cgJsData[gid].vars.categoriesLength<1){
        noCategories = true;
    }

    // First search all fields for info!
    // Get realIds out of search input
    cgJsData[gid].vars.searchInput = (!cgJsData[gid].vars.searchInput || typeof cgJsData[gid].vars.searchInput != 'string') ? '': cgJsData[gid].vars.searchInput;

    cgJsData[gid].vars.searchInputCollectedIdsWithoutCategoryDependency = [];

    if(cgJsData[gid].vars.searchInput.trim()!='' && cgJsData[gid].options.pro.Search==1){
        var val = cgJsData[gid].vars.searchInput;

        var valArray = val.split(" ");

        var valArrayNew = [];

        // Build array from values that were entered
        for(var key in valArray){

            if(!valArray.hasOwnProperty(key)){
                break;
            }

            if (valArray[key] != '') {
                valArrayNew.push(valArray[key]);
            }

        }

        for(var realId in cgJsData[gid].fullImageInfoData){
            var fullImageInfoValue;

            if(!cgJsData[gid].fullImageInfoData.hasOwnProperty(realId)){
                break;
            }

            fullImageInfoValue = cgJsData[gid].fullImageInfoData[realId];

            if (typeof fullImageInfoValue !== 'string') {
                continue;
            }

            // Iterate through the entered values
            for(var keyNew in valArrayNew){

                if(!valArrayNew.hasOwnProperty(keyNew)){
                    break;
                }

                // Add values to the existing ids; if no value is found, the id is omitted
                if(fullImageInfoValue.toLowerCase().indexOf(valArrayNew[keyNew].toLowerCase())>=0){
                    ids[realId] = val;
                    cgJsData[gid].vars.searchInputCollectedIdsWithoutCategoryDependency.push(realId);
                }else{// check for nicknames also
                    for(var WpUserId in cgJsData[gid].vars.nicknames){
                        if(!cgJsData[gid].vars.nicknames.hasOwnProperty(WpUserId)){
                            break;
                        }
                        if(cgJsData[gid].vars.rawData[realId]['WpUserId']==WpUserId && cgJsData[gid].vars.nicknames[WpUserId].toLowerCase().indexOf(valArrayNew[keyNew].toLowerCase())>=0){
                            ids[realId] = val;
                            cgJsData[gid].vars.searchInputCollectedIdsWithoutCategoryDependency.push(realId);
                        }
                    }
                }

            }

            // If there are categories and one of the ids is not in the categories, then remove it
            // If the widget is activated and categories were removed
            if(cgJsData[gid].vars.categoriesLength>=1 && cgJsData[gid].options.pro.CatWidget==1){

                // Category check here!
                var imageCatId = cgJsData[gid].vars.rawData[realId]['Category'];
                var checkCatId = false;

                for(var categoryId in cgJsData[gid].vars.categories){

                    if(!cgJsData[gid].vars.categories.hasOwnProperty(categoryId)){
                        break;
                    }

                    if(categoryId==imageCatId){

                        checkCatId = true;
                        // Also delete if it is not checked!
                        if(cgJsData[gid].vars.categories[categoryId]['Checked']==false){
                            delete ids[realId];// Delete from categories!
                        }

                        break;
                    }

                }

                // Delete if it is not available in the categories!
                if(checkCatId==false){

                    if(ids.hasOwnProperty(realId)){

                        delete ids[realId];// Delete from categories!
                    }

                }

            }

        }
    }else{

        for(var realIdNoSearch in cgJsData[gid].vars.rawData){

            if(!cgJsData[gid].vars.rawData.hasOwnProperty(realIdNoSearch)){
                break;
            }

            ids[realIdNoSearch] = '';
            cgJsData[gid].vars.searchInputCollectedIdsWithoutCategoryDependency.push(realIdNoSearch);
        }

        // If there are categories and one of the ids is not in the categories, then remove it
        // If the widget is activated and categories were removed
        if(cgJsData[gid].vars.categoriesLength>=1 && cgJsData[gid].options.pro.CatWidget==1){

            for(var realIdFilter in cgJsData[gid].vars.rawData){

                if(!cgJsData[gid].vars.rawData.hasOwnProperty(realIdFilter)){
                    break;
                }

                // Category check here!
                var imageCatIdFilter = cgJsData[gid].vars.rawData[realIdFilter]['Category'];
                var checkCatIdFilter = false;

                for(var categoryIdFilter in cgJsData[gid].vars.categories){

                    if(!cgJsData[gid].vars.categories.hasOwnProperty(categoryIdFilter)){
                        break;
                    }

                    if(categoryIdFilter==imageCatIdFilter){

                        checkCatIdFilter = true;
                        // Also delete if it is not checked!
                        if(cgJsData[gid].vars.categories[categoryIdFilter]['Checked']==false){
                            delete ids[realIdFilter];// Delete from categories!
                        }

                        break;
                    }

                }

                // Delete if it is not available in the categories!
                if(checkCatIdFilter==false){

                    if(ids.hasOwnProperty(realIdFilter)){

                        delete ids[realIdFilter];// Delete from categories!
                    }

                }

            }

        }

    }

    return ids;

};
