cgJsClass.gallery.function.message.setScrollForContainerIfRequired = function ($cgMessagesContainer, isRemoveClassCgHide) {
    var windowHeight;
    var maxHeight;
    var $cgMessagesContent = $cgMessagesContainer.find('#cgMessagesContent');
    var cgMessagesContainerCurrentMaxHeight;
    var cgMessagesContainerHeight;
    var $cg_gallery_rating_div_five_star_details_con_entry;

    cgJsClass.gallery.function.general.tools.syncViewportCssVars();
    windowHeight = cgJsClass.gallery.function.general.tools.getViewportHeight() || jQuery(window).height();
    maxHeight = windowHeight / 100 * 95 - 50;
    $cgMessagesContent.css('max-height', maxHeight + 'px');
    $cgMessagesContainer.addClass('cg_visibility_hidden');

    if (isRemoveClassCgHide) {
        $cgMessagesContainer.removeClass('cg_hide');
    }

    cgMessagesContainerCurrentMaxHeight = parseInt($cgMessagesContent.css('max-height'), 10);
    $cgMessagesContent.css('max-height', 'unset');
    cgMessagesContainerHeight = $cgMessagesContainer.outerHeight();

    if (cgMessagesContainerHeight > windowHeight / 100 * 75) {
        $cgMessagesContent.addClass('cg_overflow_y_scroll');
    } else {
        $cgMessagesContent.removeClass('cg_overflow_y_scroll');
    }

    $cgMessagesContent.css('max-height', cgMessagesContainerCurrentMaxHeight + 'px');
    $cg_gallery_rating_div_five_star_details_con_entry = $cgMessagesContent.find('.cg_gallery_rating_div_five_star_details_con_entry');

    if ($cg_gallery_rating_div_five_star_details_con_entry.length) {
        $cg_gallery_rating_div_five_star_details_con_entry.css('max-height', (cgMessagesContainerCurrentMaxHeight / 2) + 'px');
    }

    $cgMessagesContainer.removeClass('cg_visibility_hidden');
};
