        urlObject = new URL(normalizedUrl, window.location.origin);
        navigationKeys = cgJsClass.gallery.function.general.tools.getNavigationParamKeys();

        for (index = 0; index < navigationKeys.length; index++) {
            urlObject.searchParams.delete(navigationKeys[index]);
        }

        urlObject.hash = '';

        return urlObject.toString();
