cgJsClass.gallery.views.fullwindow.closeActiveUploadFormLayer = function (gid, restoreUrl) {
    var uploadLayerInfo = cgJsClass.gallery.views.fullwindow.getActiveUploadFormLayerInfo();
    var uploadGid = uploadLayerInfo.uploadGid ||
        (parseInt(gid, 10) || 0) ||
        (parseInt(cgJsClass.gallery.vars.openedUploadFormGalleryId, 10) || 0) ||
        (parseInt(cgJsClass.gallery.vars.fullwindow, 10) || 0);
    var historyState = window.history ? window.history.state : null;
    var canUseHistoryAwareClose = !!(
        cgJsClass.gallery.upload &&
        cgJsClass.gallery.upload.functions &&
        cgJsClass.gallery.upload.functions.closeLocally &&
        window.history &&
        window.history.replaceState &&
        historyState &&
        historyState.cgUploadFormOpened &&
        historyState.cgUploadReturnUrl
    );
    var closeResult = false;

    if (!uploadLayerInfo.active) {
        return false;
    }

    if (cgJsClass.gallery.upload &&
        cgJsClass.gallery.upload.functions) {
        if (canUseHistoryAwareClose) {
            closeResult = cgJsClass.gallery.upload.functions.closeLocally(uploadGid);
        } else if (restoreUrl && cgJsClass.gallery.upload.functions.close) {
            closeResult = cgJsClass.gallery.upload.functions.close(uploadGid, true, true);
        } else if (cgJsClass.gallery.upload.functions.close) {
            closeResult = cgJsClass.gallery.upload.functions.close(uploadGid);
        }
    } else if (uploadLayerInfo.$uploadLayer && uploadLayerInfo.$uploadLayer.length) {
        uploadLayerInfo.$uploadLayer.addClass('cg_hide');
        cgJsClass.gallery.vars.dom.body.removeClass('cg_upload_modal_opened cg_upload_in_progress cg_uncloseable');
        closeResult = true;
    }

    if (restoreUrl && gid && !canUseHistoryAwareClose) {
        cgJsClass.gallery.views.fullwindow.restoreFullWindowHistoryGuardUrl(gid);
    }

    return closeResult !== false;
};

