        var $infoRatingCommentDiv;
        var inputSubTitleId;
        var inputThirdTitleId;
        var isSocialRequired;
        var postTitle;
        var postAlt;
        var cg_append_file_type;
        var imageObject;
        var cgShowPositionHelper;
