                $container.removeClass('cg_hide cg_hidden cg-cat-select-area-show-more-available cg-cat-select-area-show-less-available');
                $catArea.removeClass('cg_hide').addClass('cg_hidden');
                $container.removeClass('cg-cat-select-area-show-more-available');
                $container.find('.cg-cat-select-area-show-more, .cg-cat-select-area-show-less').addClass('cg_hide');
