            var $btnShowLess = $container.find('.cg-cat-select-area-show-less');

            if (showMore) {
                $catArea
                    .removeClass('cg-cat-select-area-show-more-available')
                    .addClass('cg-cat-select-area-show-less-available cg-cat-select-area-show-unfolded');
                $container
                    .removeClass('cg-cat-select-area-show-more-available')
                    .addClass('cg-cat-select-area-show-less-available');
                $btnShowMore.addClass('cg_hide');
                $btnShowLess.addClass('cg_hide');
            } else {
                $catArea.removeClass('cg-cat-select-area-show-more-available cg-cat-select-area-show-less-available cg-cat-select-area-show-unfolded');
                $container.removeClass('cg-cat-select-area-show-more-available cg-cat-select-area-show-less-available');
                $btnShowMore.addClass('cg_hide');
                $btnShowLess.addClass('cg_hide');
            }

            if (isHeaderVisibilityHidden) {
                $cg_header.addClass('cg_visibility_hidden');
            }
            if (isHeaderHidden) {
                $cg_header.addClass('cg_hide');
            }

