cgJsClass.gallery.upload.functions.initInputDate = function ($, inputSelector, valueToSet, cgCenterDivClasses, isFromBulkUploadNewImageAdded) {
    var inputSelectorToCheck = '.cg_input_date_class';
    var cgDateFormat;

    if (inputSelector) {
        inputSelectorToCheck = inputSelector;
        $(inputSelectorToCheck).removeClass('hasDatepicker').removeData('datepicker').unbind();
        $(inputSelectorToCheck).attr('id', $(inputSelectorToCheck).attr('id') + (new Date).getTime() + Math.random().toString(16).slice(2));
    }

    $(inputSelectorToCheck).datepicker({
        beforeShow: function (input, inst) {
            var $uiDatepickerDiv = $('#ui-datepicker-div');
            var $cg_form_div_inputs_container = $(inst.input).parent();

            $uiDatepickerDiv.addClass('cg_upload_form_container');

            if (cgCenterDivClasses) {
                $uiDatepickerDiv.addClass(cgCenterDivClasses);
            } else {
                $uiDatepickerDiv.removeClass('cg_center_div_image_edit cg_center_white');
            }

            $uiDatepickerDiv.find('.ui-datepicker-next').attr('title', '');
            $cg_form_div_inputs_container.addClass('cg_overflow_hidden');

            if ($(input).hasClass('cg-field-id-input-content')) {
                $uiDatepickerDiv.addClass('cg_position_absolute');
                $uiDatepickerDiv.addClass('cg_hide');
            }

            setTimeout(function () {
                $uiDatepickerDiv.css('top', $(inst.input).parent().outerHeight() + 'px');
                $cg_form_div_inputs_container.removeClass('cg_overflow_hidden');
                if ($(input).hasClass('cg-field-id-input-content')) {
                    $uiDatepickerDiv.css({
                        'top': $(input).closest('.cg-center-image-info-div').height(),
                        'left': 0
                    });
                    $uiDatepickerDiv.removeClass('cg_hide');
                }
            }, 10);

            $cg_form_div_inputs_container.append($uiDatepickerDiv);
        },
        changeMonth: true,
        changeYear: true,
        monthNames: ["01", "02", "03", "04", "05", "06", "07", "08", "09", "10", "11", "12"],
        monthNamesShort: ["01", "02", "03", "04", "05", "06", "07", "08", "09", "10", "11", "12"],
        yearRange: "-100:+100"
    });

    if (inputSelector && !isFromBulkUploadNewImageAdded) {
        cgDateFormat = $(inputSelectorToCheck).attr('data-cg-date-format').toLowerCase().replace('yyyy', 'yy');
        $(inputSelectorToCheck).datepicker("option", "dateFormat", cgDateFormat);
        $(inputSelectorToCheck).val(valueToSet);
    } else {
        if (isFromBulkUploadNewImageAdded && inputSelectorToCheck) {
            cgDateFormat = $(inputSelectorToCheck).closest('.cg_form_div').find('.cg_date_format').val().toLowerCase().replace('yyyy', 'yy');
            $(inputSelectorToCheck).datepicker("option", "dateFormat", cgDateFormat);
        } else {
            $(inputSelectorToCheck).each(function () {
                var localDateFormat = $(this).closest('.cg_form_div').find('.cg_date_format').val().toLowerCase().replace('yyyy', 'yy');
                $(this).datepicker("option", "dateFormat", localDateFormat);
            });
        }
    }
};

cgJsClass.gallery.upload.functions.initInputDatesInUploadForm = function ($, $mainCGdivUploadForm) {
    var retryCount;
    var $dateInputs;

    if (!$mainCGdivUploadForm || !$mainCGdivUploadForm.length) {
        return;
    }

    $dateInputs = $mainCGdivUploadForm.find('.cg_input_date_class');
    if (!$dateInputs.length) {
        return;
    }

    if (!$.fn || !$.fn.datepicker) {
        retryCount = parseInt($mainCGdivUploadForm.attr('data-cg-datepicker-init-retry'), 10) || 0;
        if (retryCount < 20) {
            $mainCGdivUploadForm.attr('data-cg-datepicker-init-retry', retryCount + 1);
            setTimeout(function () {
                cgJsClass.gallery.upload.functions.initInputDatesInUploadForm($, $mainCGdivUploadForm);
            }, 100);
        }
        return;
    }

    $mainCGdivUploadForm.removeAttr('data-cg-datepicker-init-retry');
    $dateInputs.each(function () {
        var $input = $(this);

        if ($input.hasClass('hasDatepicker') && $input.data('datepicker')) {
            return;
        }

        if (!$input.closest('.cg_form_div').find('.cg_date_format').length) {
            return;
        }

        cgJsClass.gallery.upload.functions.initInputDate($, $input, undefined, undefined, true);
    });
};

