cgJsClass.gallery.upload.functions.closeLocally = function (gid) {
    var historyState = window.history ? window.history.state : null;
    var uploadReturnState = {};

    gid = cgJsClass.gallery.upload.functions.resolveCloseGalleryId(gid);

    cgJsClass.gallery.vars.isGalleryUploadFormHashChange = false;

    if (window.history && window.history.replaceState && historyState && historyState.cgUploadFormOpened && historyState.cgUploadReturnUrl) {
        uploadReturnState = historyState.cgUploadReturnState;

        if (!uploadReturnState || typeof uploadReturnState !== 'object') {
            uploadReturnState = {};
        }

        window.history.replaceState(uploadReturnState, document.title, historyState.cgUploadReturnUrl);
        return cgJsClass.gallery.upload.functions.close(gid, false, true);
    }

    return cgJsClass.gallery.upload.functions.close(gid);
};

cgJsClass.gallery.upload.functions.close = function (gid, isFromHashChange, isUrlHandledAlready) {
    var $mainCGdivHelperParent;
    var $cg_user_registry_div;
    var $cg_user_registry_div_pin_parent;
    var $mainCGdivUploadForm;
    var visibleLayerInfo;
    var activeGalleryId;
    var isStaleBodyUploadInProgress = false;
    var isVisibleUploadInProgress = false;
    var shouldBlockClose = false;
    var effectiveGid;

    if (!isUrlHandledAlready) {
        if (location.href.indexOf('#!gallery') > -1 && cgJsClass.gallery.vars.fullwindow && isFromHashChange) {
            // Do nothing during hash navigation in fullwindow mode
        } else {
            cgJsClass.gallery.function.general.tools.replaceStateOnCloseOrMinimize();
        }
    }

    visibleLayerInfo = cgJsClass.gallery.upload.functions.getVisibleLayerInfo(gid);
    effectiveGid = visibleLayerInfo.uploadGid || (parseInt(gid, 10) || 0);
    activeGalleryId = parseInt(cgJsClass.gallery.upload.vars.activeGalleryId, 10) || 0;

    if (visibleLayerInfo.$uploadLayer && visibleLayerInfo.$uploadLayer.length) {
        $mainCGdivUploadForm = visibleLayerInfo.$uploadLayer.hasClass('mainCGdivUploadForm') ?
            visibleLayerInfo.$uploadLayer :
            visibleLayerInfo.$uploadLayer.closest('.mainCGdivUploadForm');
    }

    if ((!$mainCGdivUploadForm || !$mainCGdivUploadForm.length) && effectiveGid) {
        $mainCGdivUploadForm = jQuery('#mainCGdivUploadForm' + effectiveGid);
    }

    isVisibleUploadInProgress = !!(
        $mainCGdivUploadForm &&
        $mainCGdivUploadForm.length &&
        $mainCGdivUploadForm.hasClass('cg_upload_in_progress')
    );

    isStaleBodyUploadInProgress = !!(
        cgJsClass.gallery.vars.dom.body.hasClass('cg_upload_in_progress') &&
        !isVisibleUploadInProgress &&
        (!activeGalleryId || !effectiveGid || String(activeGalleryId) !== String(effectiveGid))
    );

    if (isStaleBodyUploadInProgress) {
        cgJsClass.gallery.vars.dom.body.removeClass('cg_upload_in_progress cg_uncloseable');
        cgJsClass.gallery.vars.dom.html.removeClass('cg_pointer_events_none cg_overflow_hidden');
        cgJsClass.gallery.upload.vars.activeGalleryId = 0;
    }

    shouldBlockClose = !!(
        cgJsClass.gallery.vars.dom.body.hasClass('cg_upload_in_progress') &&
        !isStaleBodyUploadInProgress
    );

    if (shouldBlockClose) {
        return false;
    }

    cgJsClass.gallery.function.general.tools.backdropHide();

    if (cgJsClass.gallery.vars.fullwindow && effectiveGid && cgJsData[effectiveGid] && cgJsData[effectiveGid].vars) {
        $mainCGdivHelperParent = cgJsData[effectiveGid].vars.mainCGdivHelperParent;
        $mainCGdivHelperParent.removeClass('cg_no_scroll');
    }

    cgJsClass.gallery.vars.dom.html.removeClass('cg_no_scroll');
    cgJsClass.gallery.vars.dom.body.removeClass('cg_upload_modal_opened cg_uncloseable');

    $cg_user_registry_div = jQuery('.mainCGdivPinOpened');
    if ($cg_user_registry_div.length) {
        $cg_user_registry_div_pin_parent = effectiveGid ? jQuery('#mainCGdiv' + effectiveGid + ' #cg_user_registry_div_pin_parent') : jQuery();
        if ($cg_user_registry_div_pin_parent.length) {
            $cg_user_registry_div_pin_parent.append($cg_user_registry_div.removeClass('mainCGdivPinOpened'));
        } else {
            $cg_user_registry_div.removeClass('mainCGdivPinOpened').addClass('cg_hide');
        }
    } else if ($mainCGdivUploadForm && $mainCGdivUploadForm.length) {
        if (effectiveGid) {
            $mainCGdivUploadForm.addClass('cg_hide').prependTo('#cgGalleryViewSortControl' + effectiveGid);
        } else {
            $mainCGdivUploadForm.addClass('cg_hide');
        }
    } else if (visibleLayerInfo.$uploadLayer && visibleLayerInfo.$uploadLayer.length) {
        visibleLayerInfo.$uploadLayer.addClass('cg_hide');
    }

    cgJsClass.gallery.vars.openedUploadFormGalleryId = null;

    if (
        effectiveGid &&
        cgJsClass.gallery.resize &&
        cgJsClass.gallery.resize.clearFullwindowKeyboardInteraction
    ) {
        cgJsClass.gallery.resize.clearFullwindowKeyboardInteraction(effectiveGid, 'upload');
    }

    if (effectiveGid) {
        cgJsClass.gallery.upload.functions.applyUploadFocusActionForLoadedGalleries(effectiveGid, 'consumePendingUploadFocusAction');
    }

    cgJsClass.gallery.vars.isGalleryUploadFormHashChange = false;

    return true;
};

