        parsedHtml = parser.parseFromString(response, 'text/html');
        script = jQuery(parsedHtml).find('script[data-cg-processing="true"]').first().html();

        eval(script);

        cgJsClass.gallery.categories.checkIfShowMoreForCatAreaRequired(gid, undefined, undefined, true);

        $mainCGdivUploadForm = cgJsData[gid].vars.mainCGdivUploadForm;

        $mainCGdivUploadForm.find('.cg_form_div_image_upload').removeClass('cg_form_div_error');
        $mainCGdivUploadForm.find('.cg_form_div_image_upload > .cg_hide_image_upload.cg_input_error').addClass('cg_hide');
