            cgJsData[gid].vars.info[realId] &&
            cgJsData[gid].vars.info[realId][cgJsData[gid].options.visual['Field3IdGalleryView']] &&
            cgJsData[gid].vars.info[realId][cgJsData[gid].options.visual['Field3IdGalleryView']]['field-content']
