                if (cgCatId !== null) {
                    cgJsData[gid].vars.rawData[realId]['Category'] = cgCatId;
                }

                currentInfoData = (cgJsData[gid].vars.info && cgJsData[gid].vars.info[realId]) ? cgJsData[gid].vars.info[realId] : {};
                cgJsClass.gallery.info.collectInfo(gid, realId, currentInfoData);
                cgJsClass.gallery.views.singleViewFunctions.editCloseInfoUserGallery($cgCenterDiv);

