function cgGoogleSignInRenderButton() {
    if (cgJsClass.gallery.function.general.tools.getLocalStorageItem('cgSignedIn')) {
        cgJsClass.gallery.function.general.tools.removeLocalStorageItem('cgSignedIn');
        return;
    }

    if (window.gapi && window.gapi.load) {
        window.gapi.load('auth2', function () {

            function onInit(success) {
                var authInstance;
                var signedIn;

                if (!cgGapiAuth2OnInitAlreadyExecuted) {
                    cgGapiAuth2OnInitAlreadyExecuted = true;
                } else {
                    return;
                }

                gapi.signin2.render('cgGoogleSignIn', {
                    'scope': 'profile email',
                    'width': 'auto',
                    'height': cgGoogleButtonSizeHeight,
                    'longtitle': true,
                    'text': cgGoogleButtonTextOnLoad,
                    'theme': cgGoogleButtonStyle,
                    'onsuccess': cgGoogleOnSignInSuccessLogin,
                    'onfailure': cgGoogleOnSignInFailureOrCloseLogin
                });

                if (!cgGoogleOnPageLoadApiCheckDone) {
                    cgGoogleOnPageLoadApiCheckDone = true;
                    authInstance = window.gapi.auth2.getAuthInstance();
                    cgGoogleObject.authInstance = authInstance;
                    signedIn = authInstance.isSignedIn.get();

                    if (signedIn) {
                        cgGoogleObject.isSignedIn = true;
                        cgGoogleButtonTextOnLoad = authInstance.currentUser.get().getBasicProfile().getName();
                    } else {
                        cgRenderNicknameButtonsOrDependencies();
                    }
                }
            }

            function onError(error) {
                var errorString = '';
                
                if (error && error.error === "idpiframe_initialization_failed") {
                    errorString = error.details;
                } else if (error && error.details) {
                    errorString = error.details;
                }

                jQuery('.cgGoogleSignInContainerParent').each(function () {
                    var $cgGoogleSignIn;
                    jQuery(this).find('.cgGoogleSignLibError').val(1);
                    $cgGoogleSignIn = jQuery(this).find('.cgGoogleSignIn');
                    $cgGoogleSignIn.html('<div class="abcRioButton" style="display:block;padding: 5px 10px;text-align:center;"><div>' + errorString + '</div></div>');
                    jQuery(this).find('.cgGoogleSignInContainer').removeClass('cg_visibility_hidden');
                    jQuery(this).removeClass('cg_hide');
                });
            }

            gapi.auth2.init({
                client_id: jQuery('#cgGoogleSignInClientId').val(),
                scope: 'profile'
            }).then(onInit, onError);
        });
    }
}

