;/**
 * @ai_scan_directive
 * Context: Contest Gallery Plugin - Ecommerce UI and Core Functions
 * Description: Contains various helper functions for the eCommerce/Checkout process.
 * Includes checking if a video is for sale, verifying internet connectivity,
 * synchronizing billing and shipping address fields, validating required checkout inputs
 * and agreements, calculating cart totals, and rendering embed objects (YouTube, Instagram, etc.).
 */
cgJsClass.gallery.ecommerce.functions.checkIfVideoForSale = function (ImgType, gid, realId, multipleFilesOrder) {
    var isForSale = false;
    var rawDataObj = cgJsData[gid].vars.rawData[realId];

    if (rawDataObj.ecommerceData && rawDataObj.ecommerceData['IsDownload'] == '1' && rawDataObj.ecommerceData['WpUploadFilesForSale']) {

        var filesForSaleArray = Object.values(rawDataObj.ecommerceData['WpUploadFilesForSale']);
        var wpUploadToCheck = multipleFilesOrder
            ? rawDataObj.MultipleFilesParsed[multipleFilesOrder].WpUpload.toString()
            : rawDataObj.WpUpload.toString();

        if (multipleFilesOrder) {
            // For multiple files, video type restriction applies
            var validVideoTypes = ['mp4', 'avi', 'webm', 'wmv', 'mov'];
            if (validVideoTypes.indexOf(ImgType) > -1 && filesForSaleArray.indexOf(wpUploadToCheck) > -1) {
                isForSale = true;
            }
        } else {
            // Standard single file check
            if (filesForSaleArray.indexOf(wpUploadToCheck) > -1) {
                isForSale = true;
            }
        }
    }
    return isForSale;
};

cgJsClass.gallery.ecommerce.functions.isOnlineCheck = function (isFromCheckoutButtonsLoadError) {
    var ecommerceVars = cgJsClass.gallery.vars.ecommerce;

    var cgShowCheckoutNotPossibleMessage = function () {
        cgJsClass.gallery.vars.isEcommerceButtonsLoaded = true;
        ecommerceVars.$cgEcommerceCheckoutBodyContainer.find('#cgEcommerceCheckoutBodyContainerClose').removeClass('cg_hide');
        cgJsClass.gallery.vars.dom.body.removeClass('cg_pointer_events_none');
        ecommerceVars.$cgEcommerceCheckoutBodyContainer.removeClass('cg_overflow_hidden');
        cgJsClass.gallery.ecommerce.functions.checkoutContainerClose();
    };

    var cgIsOnlineCheck = async function (isFromCheckoutButtonsLoadError) {
        if (!window.navigator.onLine) {
            return false;
        }

        var url = new URL(window.location.origin);
        url.searchParams.set('rand', String(new Date().getTime() / 1000));

        try {
            var response = await fetch(url.toString(), { method: 'HEAD' });

            if ((!response.ok || ecommerceVars.isNotOnlineForTest) && !ecommerceVars.isDoNotCheckForOnline) {
                cgShowCheckoutNotPossibleMessage();
                // Note: gid is assumed to be available in the higher scope where this is called
                cgJsClass.gallery.function.message.showPro(gid, cgJsClass.gallery.language.ecommerce.CheckoutImpossibleNoInternet);
            } else if (isFromCheckoutButtonsLoadError && response.ok) {
                cgJsClass.gallery.function.message.showPro(gid, '<span style="text-align: center; display: inline-block; width: 100%;">PayPal buttons could not be loaded,<br>wrong Client ID or wrong Secret<br>or no internet connection</span>');
            }
            return response.ok;
        } catch (e) {
            cgShowCheckoutNotPossibleMessage();
            cgJsClass.gallery.function.message.showPro(gid, cgJsClass.gallery.language.ecommerce.CheckoutImpossibleNoInternet);
        }
    };

    cgIsOnlineCheck(isFromCheckoutButtonsLoadError);
};

