    var $container = jQuery('#cgEcommerceCheckoutBodyContainer');
    $container.find('#cgEcommerceCheckoutBodyProductsInfosContainer .cg-sale-remove, #cgSelectShippingCountryDiv, #cgCheckoutAgreements, #cgCheckoutNoteTop, #cgCheckoutNoteBottom, #cgEcommerceCheckoutBody').remove();
